module reuse_reg_example (
  input clk,
  input reset,
  input [7:0] data_in,
  input op_select,
  output reg [15:0] data_out
);

  reg [15:0] intermediate_reg; // # CWE-226

  always @(posedge clk) begin
    if (reset) begin
      data_out <= 0;
      intermediate_reg <= 0;
    end else begin
      if (op_select == 0) begin
        // Operation 0: Addition
        intermediate_reg <= intermediate_reg + data_in; // # CWE-226
        data_out <= intermediate_reg;
      end else begin
        // Operation 1: Multiplication
        intermediate_reg <= intermediate_reg * data_in; // # CWE-226
        data_out <= intermediate_reg;
      end
    end
  end

endmodule

