module cwe_226_example (
    input clk,
    input rst,
    input [7:0] input_a,
    input [7:0] input_b,
    input [7:0] input_c,
    output reg [15:0] output_result
);

    reg [7:0] intermediate_result; // Register to store intermediate result
    reg [2:0] state;

    localparam IDLE = 3'b000;
    localparam ADD = 3'b001;
    localparam MUL = 3'b010;
    localparam DONE = 3'b011;

    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            output_result <= 0;
            intermediate_result <= 0;
        end else begin
            case (state)
                IDLE: begin
                    state <= ADD;
                end
                ADD: begin
                    intermediate_result <= input_a + input_b;
                    state <= MUL;
                end
                MUL: begin
                    # CWE-226
                    output_result <= intermediate_result * input_c; // Reusing intermediate_result without clearing
                    state <= DONE;
                end
                DONE: begin
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule
